import{_ as e,c as a,o as t,d as n}from"./app.05a75977.js";const g=JSON.parse('{"title":"Chapter 5: Representing Data for Machines","description":"","frontmatter":{},"headers":[{"level":2,"title":"5.1 Why Representation Matters","slug":"_5-1-why-representation-matters","link":"#_5-1-why-representation-matters","children":[]},{"level":2,"title":"5.2 Everything Becomes Numbers","slug":"_5-2-everything-becomes-numbers","link":"#_5-2-everything-becomes-numbers","children":[]},{"level":2,"title":"5.3 Types of Data (Important for Encoding)","slug":"_5-3-types-of-data-important-for-encoding","link":"#_5-3-types-of-data-important-for-encoding","children":[{"level":3,"title":"Numerical Data","slug":"numerical-data","link":"#numerical-data","children":[]},{"level":3,"title":"Categorical Data","slug":"categorical-data","link":"#categorical-data","children":[]},{"level":3,"title":"Nominal Data","slug":"nominal-data","link":"#nominal-data","children":[]},{"level":3,"title":"Ordinal Data","slug":"ordinal-data","link":"#ordinal-data","children":[]},{"level":3,"title":"Explanation","slug":"explanation","link":"#explanation","children":[]}]},{"level":2,"title":"5.4 Label Encoding","slug":"_5-4-label-encoding","link":"#_5-4-label-encoding","children":[{"level":3,"title":"Explanation","slug":"explanation-1","link":"#explanation-1","children":[]}]},{"level":2,"title":"5.5 One-Hot Encoding","slug":"_5-5-one-hot-encoding","link":"#_5-5-one-hot-encoding","children":[{"level":3,"title":"Explanation","slug":"explanation-2","link":"#explanation-2","children":[]}]},{"level":2,"title":"5.6 Numerical Data (Revisited)","slug":"_5-6-numerical-data-revisited","link":"#_5-6-numerical-data-revisited","children":[]},{"level":2,"title":"5.7 Why Representation Impacts Models","slug":"_5-7-why-representation-impacts-models","link":"#_5-7-why-representation-impacts-models","children":[]},{"level":2,"title":"5.8 A Clear Mental Model","slug":"_5-8-a-clear-mental-model","link":"#_5-8-a-clear-mental-model","children":[]},{"level":2,"title":"5.9 Why This Chapter Matters","slug":"_5-9-why-this-chapter-matters","link":"#_5-9-why-this-chapter-matters","children":[]},{"level":2,"title":"5.10 What Comes Next","slug":"_5-10-what-comes-next","link":"#_5-10-what-comes-next","children":[]},{"level":2,"title":"Chapter Summary","slug":"chapter-summary","link":"#chapter-summary","children":[]}],"relativePath":"ml-foundation/en/part1/representing-data-for-machines.md"}'),i={name:"ml-foundation/en/part1/representing-data-for-machines.md"},r=n('<h1 id="chapter-5-representing-data-for-machines" tabindex="-1">Chapter 5: Representing Data for Machines <a class="header-anchor" href="#chapter-5-representing-data-for-machines" aria-hidden="true">#</a></h1><hr><h2 id="_5-1-why-representation-matters" tabindex="-1">5.1 Why Representation Matters <a class="header-anchor" href="#_5-1-why-representation-matters" aria-hidden="true">#</a></h2><ul><li>Machines do not understand text, images, or categories directly</li><li>Machines understand only <strong>numbers</strong></li></ul><blockquote><p>Every type of data must be converted into numbers before using it in Machine Learning.</p></blockquote><p>In real-world problems, data comes in many forms such as text, categories, or labels. However, Machine Learning models work using mathematical operations, and for that, everything must be represented numerically. This process of converting raw data into numbers is called <strong>data representation</strong>, and it is a critical step before training any model.</p><hr><h2 id="_5-2-everything-becomes-numbers" tabindex="-1">5.2 Everything Becomes Numbers <a class="header-anchor" href="#_5-2-everything-becomes-numbers" aria-hidden="true">#</a></h2><ul><li>Text \u2192 numbers</li><li>Categories \u2192 numbers</li><li>Boolean values \u2192 numbers (0/1)</li></ul><blockquote><p>If data is not numeric, the model cannot process it.</p></blockquote><p>For example:</p><ul><li>\u201CYes\u201D \u2192 1, \u201CNo\u201D \u2192 0</li><li>Words \u2192 numerical representations</li><li>Images \u2192 pixel values (numbers)</li></ul><p>No matter how complex the data looks, behind the scenes, it is always converted into numbers. This is the only language a machine understands.</p><hr><h2 id="_5-3-types-of-data-important-for-encoding" tabindex="-1">5.3 Types of Data (Important for Encoding) <a class="header-anchor" href="#_5-3-types-of-data-important-for-encoding" aria-hidden="true">#</a></h2><ul><li><p>Numerical data</p></li><li><p>Categorical data:</p><ul><li>Nominal</li><li>Ordinal</li></ul></li></ul><blockquote><p>Understanding data type helps in choosing the correct encoding method.</p></blockquote><p>Before converting data into numbers, it is important to understand what type of data we are dealing with. Different types of data require different handling methods. Choosing the wrong method can confuse the model and reduce performance.</p><hr><h3 id="numerical-data" tabindex="-1">Numerical Data <a class="header-anchor" href="#numerical-data" aria-hidden="true">#</a></h3><ul><li>Data in the form of numbers</li><li>Can be used directly</li></ul><p>Examples:</p><ul><li>Age = 25</li><li>Salary = 50,000</li><li>Temperature = 32.5\xB0C</li></ul><p>Numerical data already has mathematical meaning, so models can directly use it. However, in some cases, we still need to scale or normalize it, which we will learn later.</p><hr><h3 id="categorical-data" tabindex="-1">Categorical Data <a class="header-anchor" href="#categorical-data" aria-hidden="true">#</a></h3><ul><li>Data that represents categories</li><li>Cannot be used directly</li></ul><p>Examples:</p><ul><li>Color: Red, Blue</li><li>City: Mumbai, Delhi</li></ul><p>Categorical data does not have direct numerical meaning, so we must convert it into numbers carefully.</p><hr><h3 id="nominal-data" tabindex="-1">Nominal Data <a class="header-anchor" href="#nominal-data" aria-hidden="true">#</a></h3><ul><li>Categories with <strong>no order</strong></li></ul><p>Examples:</p><ul><li>Color: Red, Blue, Green</li><li>City: Mumbai, Delhi</li></ul><p>There is no ranking or order between categories.</p><p>Use <strong>One-Hot Encoding</strong></p><hr><h3 id="ordinal-data" tabindex="-1">Ordinal Data <a class="header-anchor" href="#ordinal-data" aria-hidden="true">#</a></h3><ul><li>Categories with <strong>meaningful order</strong></li></ul><p>Examples:</p><ul><li>Size: Small, Medium, Large</li><li>Education: School, College, PhD</li></ul><p>Here, order matters.</p><p>Use <strong>Label Encoding (carefully)</strong></p><hr><h3 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-hidden="true">#</a></h3><p>The difference between nominal and ordinal data is very important. If we treat unordered data as ordered, the model may learn incorrect patterns. For example, assigning numbers to colors may imply that one color is \u201Cgreater\u201D than another, which is not true. However, for ordered data like \u201CSmall &lt; Medium &lt; Large,\u201D numerical encoding makes sense because there is a natural ranking.</p><hr><h2 id="_5-4-label-encoding" tabindex="-1">5.4 Label Encoding <a class="header-anchor" href="#_5-4-label-encoding" aria-hidden="true">#</a></h2><ul><li>Converts categories into numbers</li><li>Each category gets a unique number</li></ul><p>Example:</p><ul><li>Small \u2192 0</li><li>Medium \u2192 1</li><li>Large \u2192 2</li></ul><p>Label Encoding is simple and useful when there is a natural order in the data.</p><hr><h3 id="explanation-1" tabindex="-1">Explanation <a class="header-anchor" href="#explanation-1" aria-hidden="true">#</a></h3><p>Label encoding assigns a number to each category. It works well for ordinal data where order matters. However, it should be used carefully for nominal data, as it may introduce a false sense of ranking.</p><hr><h2 id="_5-5-one-hot-encoding" tabindex="-1">5.5 One-Hot Encoding <a class="header-anchor" href="#_5-5-one-hot-encoding" aria-hidden="true">#</a></h2><ul><li>Converts categories into binary columns</li><li>Each category becomes a separate feature</li></ul><p>Example:</p><table><thead><tr><th>Color</th><th>Red</th><th>Blue</th><th>Green</th></tr></thead><tbody><tr><td>Red</td><td>1</td><td>0</td><td>0</td></tr><tr><td>Blue</td><td>0</td><td>1</td><td>0</td></tr></tbody></table><p>One-Hot Encoding ensures that all categories are treated equally.</p><hr><h3 id="explanation-2" tabindex="-1">Explanation <a class="header-anchor" href="#explanation-2" aria-hidden="true">#</a></h3><p>Instead of assigning numbers, one-hot encoding creates separate columns for each category. Only one column is marked as \u201C1\u201D while others remain \u201C0.\u201D This removes any false ordering and is widely used for nominal data.</p><hr><h2 id="_5-6-numerical-data-revisited" tabindex="-1">5.6 Numerical Data (Revisited) <a class="header-anchor" href="#_5-6-numerical-data-revisited" aria-hidden="true">#</a></h2><ul><li>Already numeric</li><li>May need scaling later</li></ul><p>Examples:</p><ul><li>Age</li><li>Income</li><li>Distance</li></ul><p>Even though numerical data can be used directly, differences in scale (like age vs salary) can affect model performance. This is why scaling becomes important, which we will explore in later chapters.</p><hr><h2 id="_5-7-why-representation-impacts-models" tabindex="-1">5.7 Why Representation Impacts Models <a class="header-anchor" href="#_5-7-why-representation-impacts-models" aria-hidden="true">#</a></h2><ul><li>Incorrect encoding \u2192 wrong learning</li><li>Proper encoding \u2192 better performance</li></ul><blockquote><p>The way data is represented directly affects how the model learns patterns.</p></blockquote><p>If data is represented incorrectly, the model may learn patterns that do not exist. For example, treating categories as ordered when they are not can mislead the model. Proper representation ensures that the model learns meaningful relationships.</p><hr><h2 id="_5-8-a-clear-mental-model" tabindex="-1">5.8 A Clear Mental Model <a class="header-anchor" href="#_5-8-a-clear-mental-model" aria-hidden="true">#</a></h2><ul><li>Machines understand only numbers</li><li>Data must be converted into numeric form</li><li>Type of data decides encoding method</li></ul><blockquote><p>Good representation = better learning</p></blockquote><hr><h2 id="_5-9-why-this-chapter-matters" tabindex="-1">5.9 Why This Chapter Matters <a class="header-anchor" href="#_5-9-why-this-chapter-matters" aria-hidden="true">#</a></h2><ul><li>Prepares data for ML models</li><li>Helps choose correct encoding</li><li>Prevents common mistakes</li></ul><p>This chapter builds a strong foundation for all upcoming steps like preprocessing, scaling, and model training.</p><hr><h2 id="_5-10-what-comes-next" tabindex="-1">5.10 What Comes Next <a class="header-anchor" href="#_5-10-what-comes-next" aria-hidden="true">#</a></h2><p>Now that you understand how to represent data correctly, the next step is:</p><blockquote><p>How to create better features from existing data</p></blockquote><p>In the next chapter, we will explore:</p><p><strong>Feature Engineering \u2014 the most powerful skill in Machine Learning</strong></p><hr><h2 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-hidden="true">#</a></h2><ul><li>Machines understand only numbers</li><li>Data must be converted into numeric form</li><li>Numerical data can be used directly</li><li>Categorical data needs encoding</li><li>Nominal \u2192 One-Hot Encoding</li><li>Ordinal \u2192 Label Encoding</li><li>Correct representation improves model performance</li></ul><hr>',94),l=[r];function o(s,d,h,c,m,u){return t(),a("div",null,l)}const f=e(i,[["render",o]]);export{g as __pageData,f as default};
